// migrate-directive-voice-49.cjs
// Rewrites directive "Contact the X at Y to confirm Z" bullets into explainer
// voice across LGLW6-D_roofing-* town/village entries.
//
// Pattern sources: 16 entries generated by earlier migrate-trades-entries-*
// scripts. The boilerplate bullet reads as instruction; converts to description
// of what that office is and what it confirms.

const fs = require("fs");
const path = require("path");

const ENTRIES_DIR = path.join(__dirname, "..", "src", "data", "legal", "entries");

const files = fs
  .readdirSync(ENTRIES_DIR)
  .filter((f) => f.startsWith("LGLW6-D_roofing-") && f.endsWith(".js"))
  .map((f) => path.join(ENTRIES_DIR, f));

// Regex patterns, applied in order. First match wins per line.
// Pattern 1: "Contact <the-office> at <phone[ ext N]> to confirm <suffix>"
// Pattern 2: "Contact <the-office> to confirm <suffix>" (no phone)
// Normalize "your roofing project" → "a roofing project" so reframed output
// is fully third-person explainer, not second-person directive-adjacent.
const PRE_NORMALIZE = [
  {
    from: /"Contact (the [^"]+? to confirm[^"]*?)your roofing project([^"]*?)"/g,
    to: '"Contact $1a roofing project$2"',
  },
];

const REGEX_RULES = [
  {
    from: /"Contact the ([^"]+?) at ([\d\-]+(?: ext \d+)?) to confirm ([^"]+?)"/g,
    to: '"The $1 ($2) is the office that confirms $3"',
  },
  {
    from: /"Contact the ([^"]+?) to confirm ([^"]+?)"/g,
    to: '"The $1 is the office that confirms $2"',
  },
];

let totalFilesChanged = 0;
let totalReplacements = 0;
const perFileLog = [];

for (const file of files) {
  let content = fs.readFileSync(file, "utf8");
  const original = content;
  let fileReplacements = 0;

  for (const { from, to } of PRE_NORMALIZE) {
    const matches = content.match(from);
    if (matches) {
      content = content.replace(from, to);
    }
  }

  for (const { from, to } of REGEX_RULES) {
    const matches = content.match(from);
    if (matches) {
      content = content.replace(from, to);
      fileReplacements += matches.length;
    }
  }

  if (content !== original) {
    fs.writeFileSync(file, content, "utf8");
    totalFilesChanged++;
    totalReplacements += fileReplacements;
    perFileLog.push(`  ${path.basename(file)}: ${fileReplacements} replacements`);
  } else {
    perFileLog.push(`  ${path.basename(file)}: no changes`);
  }
}

console.log(`\nDirective-voice migration (roofing boilerplate):`);
console.log(`  Files scanned:      ${files.length}`);
console.log(`  Files changed:      ${totalFilesChanged}`);
console.log(`  Total replacements: ${totalReplacements}`);
console.log(`\nPer-file log:`);
for (const line of perFileLog) console.log(line);

if (totalFilesChanged === 0) {
  console.error("\nABORT: no files changed. Check regex or source state.");
  process.exit(1);
}
